import type { HighlighterCore, ThemedToken } from "shiki/core";

// shared Shiki tokenizer for code primitives (Code, CodeDiff, CodeBlockEditor, Markdown) — CSS-var theme
// (not baked github-light/dark), tokens resolve `var(--code-token-*)`, revalued by the active color scope in code.css
// pure+isomorphic (RSC awaits, client highlights in effect); LRU cache (lang\ncode) keeps re-highlight cheap; null = unknown lang

export type CodeTokenStyle = {
  color?: string;
  fontStyle?: "italic" | "normal";
  fontWeight?: "bold" | "normal";
  textDecoration?: "underline";
};

export type CodeToken = { content: string; style?: CodeTokenStyle };
export type CodeTokenLine = CodeToken[];
export type CodeTokenLines = CodeTokenLine[];
export type CodeEmphasisSegment = { text: string; emphasis: boolean };
export type CodeTokenEmphasisRun = CodeToken & { emphasis: boolean };

export const CODE_THEME_NAME = "agent-code";
export const CODE_VARIABLE_PREFIX = "--code-";

const languageAliases: Record<string, string> = {
  bash: "bash",
  cjs: "javascript",
  css: "css",
  diff: "diff",
  html: "html",
  js: "javascript",
  json: "json",
  json5: "json",
  jsx: "jsx",
  markdown: "markdown",
  md: "markdown",
  mjs: "javascript",
  node: "javascript",
  py: "python",
  python: "python",
  sh: "bash",
  shell: "bash",
  ts: "typescript",
  tsx: "tsx",
  typescript: "typescript",
  yaml: "yaml",
  yml: "yaml",
  zsh: "bash",
};

// Shiki FontStyle bitmask (Italic = 1, Bold = 2, Underline = 4).
const FONT_STYLE_ITALIC = 1;
const FONT_STYLE_BOLD = 2;
const FONT_STYLE_UNDERLINE = 4;

let highlighterPromise: Promise<HighlighterCore> | null = null;

export function normalizeLanguage(language?: string | null): string | undefined {
  if (!language) return undefined;
  return languageAliases[language.toLowerCase()];
}

function getHighlighter(): Promise<HighlighterCore> {
  if (!highlighterPromise) {
    highlighterPromise = (async () => {
      const [{ createHighlighterCore, createCssVariablesTheme }, { createJavaScriptRegexEngine }] = await Promise.all([
        import("shiki/core"),
        import("shiki/engine/javascript"),
      ]);

      const theme = createCssVariablesTheme({
        name: CODE_THEME_NAME,
        variablePrefix: CODE_VARIABLE_PREFIX,
        fontStyle: true,
      });

      return createHighlighterCore({
        themes: [theme],
        langs: [
          import("shiki/langs/javascript.mjs"),
          import("shiki/langs/typescript.mjs"),
          import("shiki/langs/tsx.mjs"),
          import("shiki/langs/jsx.mjs"),
          import("shiki/langs/json.mjs"),
          import("shiki/langs/bash.mjs"),
          import("shiki/langs/markdown.mjs"),
          import("shiki/langs/python.mjs"),
          import("shiki/langs/css.mjs"),
          import("shiki/langs/html.mjs"),
          import("shiki/langs/yaml.mjs"),
          import("shiki/langs/diff.mjs"),
        ],
        engine: createJavaScriptRegexEngine(),
      });
    })();
  }

  return highlighterPromise;
}

function tokenStyle(token: ThemedToken): CodeTokenStyle | undefined {
  const style: CodeTokenStyle = {};
  if (token.color) style.color = token.color;
  const fontStyle = token.fontStyle ?? 0;
  if (fontStyle > 0) {
    if ((fontStyle & FONT_STYLE_ITALIC) !== 0) style.fontStyle = "italic";
    if ((fontStyle & FONT_STYLE_BOLD) !== 0) style.fontWeight = "bold";
    if ((fontStyle & FONT_STYLE_UNDERLINE) !== 0) style.textDecoration = "underline";
  }
  return style.color || style.fontStyle || style.fontWeight || style.textDecoration ? style : undefined;
}

// Small LRU: streaming/virtualized views re-highlight the same code repeatedly.
const CACHE_LIMIT = 200;
const cache = new Map<string, CodeTokenLines | null>();

function cacheGet(key: string): CodeTokenLines | null | undefined {
  const value = cache.get(key);
  if (value !== undefined) {
    cache.delete(key); // refresh recency
    cache.set(key, value);
  }
  return value;
}

function cacheSet(key: string, value: CodeTokenLines | null): void {
  cache.set(key, value);
  if (cache.size > CACHE_LIMIT) {
    const oldest = cache.keys().next().value;
    if (oldest !== undefined) cache.delete(oldest);
  }
}

function reconstructs(value: string, parts: readonly string[]): boolean {
  return parts.join("") === value;
}

export function mergeCodeTokenLineWithEmphasis(
  plain: string,
  tokens: CodeTokenLine | null,
  segments: readonly CodeEmphasisSegment[] | undefined,
): CodeTokenEmphasisRun[] {
  const tokenParts = tokens?.filter((token) => token.content.length > 0) ?? [];
  const validTokens = reconstructs(
    plain,
    tokenParts.map((token) => token.content),
  )
    ? tokenParts
    : [{ content: plain }];
  const segmentParts = segments?.filter((segment) => segment.text.length > 0) ?? [];
  const validSegments = reconstructs(
    plain,
    segmentParts.map((segment) => segment.text),
  )
    ? segmentParts
    : [{ text: plain, emphasis: false }];

  if (plain.length === 0) return [];

  const runs: CodeTokenEmphasisRun[] = [];
  let tokenIndex = 0;
  let segmentIndex = 0;
  let tokenOffset = 0;
  let segmentOffset = 0;

  while (tokenIndex < validTokens.length && segmentIndex < validSegments.length) {
    const token = validTokens[tokenIndex];
    const segment = validSegments[segmentIndex];
    const length = Math.min(token.content.length - tokenOffset, segment.text.length - segmentOffset);
    runs.push({
      content: token.content.slice(tokenOffset, tokenOffset + length),
      ...(token.style ? { style: token.style } : {}),
      emphasis: segment.emphasis,
    });

    tokenOffset += length;
    segmentOffset += length;
    if (tokenOffset === token.content.length) {
      tokenIndex += 1;
      tokenOffset = 0;
    }
    if (segmentOffset === segment.text.length) {
      segmentIndex += 1;
      segmentOffset = 0;
    }
  }

  return runs;
}

// null for unknown language; memoized by `lang\ncode`
export async function highlightToTokens(code: string, language?: string | null): Promise<CodeTokenLines | null> {
  const lang = normalizeLanguage(language);
  if (!lang) return null;

  const key = `${lang}\n${code}`;
  const cached = cacheGet(key);
  if (cached !== undefined) return cached;

  const highlighter = await getHighlighter();
  const { tokens } = highlighter.codeToTokens(code, { lang, theme: CODE_THEME_NAME });
  const lines: CodeTokenLines = tokens.map((line) => line.map((token) => ({ content: token.content, style: tokenStyle(token) })));

  cacheSet(key, lines);
  return lines;
}

/*
 * Control UI — code + diff tokens, derived from the shared theme contract.
 * --code-token-*: Shiki CSS-variables syntax palette (lib/code-tokens.ts) — follows active skin instead of a frozen palette. --diff-*: 3-tier diff colors (line/emphasis/gutter/fg per side), à la @pierre/diffs. Both skin-overridable via pack skin.css.
 * Scoped to the root color mode at zero specificity so every skin inherits the correct palette and can override it locally.
 */

:where(:root) {
  /* syntax — light (github-light adjacent, retinted onto the neutral token hue family) */
  --code-foreground: var(--foreground);
  --code-token-constant: oklch(0.5 0.15 250);
  --code-token-string: oklch(0.49 0.13 150);
  --code-token-string-expression: oklch(0.49 0.13 150);
  --code-token-comment: oklch(0.48 0.015 285);
  --code-token-keyword: oklch(0.53 0.2 18);
  --code-token-parameter: oklch(0.52 0.09 55);
  --code-token-function: oklch(0.54 0.17 300);
  --code-token-punctuation: oklch(0.5 0.02 285);
  --code-token-link: oklch(0.5 0.15 250);

  /* diff — light. add ≈ green (H150), del ≈ red (H22). */
  --diff-add-line: oklch(0.93 0.055 150 / 0.65);
  --diff-add-emphasis: oklch(0.86 0.11 150 / 0.8);
  --diff-add-gutter: oklch(0.91 0.07 150);
  --diff-add-fg: oklch(0.48 0.11 150);
  --diff-del-line: oklch(0.94 0.05 22 / 0.6);
  --diff-del-emphasis: oklch(0.87 0.12 22 / 0.8);
  --diff-del-gutter: oklch(0.92 0.07 22);
  --diff-del-fg: oklch(0.53 0.16 22);
  --diff-context-fg: var(--muted-foreground);
  --diff-gutter-bg: oklch(from var(--muted) l c h / 0.5);
}

:where(.dark) {
  /* syntax — dark (github-dark adjacent) */
  --code-foreground: var(--foreground);
  --code-token-constant: oklch(0.78 0.13 235);
  --code-token-string: oklch(0.8 0.13 150);
  --code-token-string-expression: oklch(0.8 0.13 150);
  --code-token-comment: oklch(0.76 0.02 285);
  --code-token-keyword: oklch(0.75 0.16 12);
  --code-token-parameter: oklch(0.82 0.09 60);
  --code-token-function: oklch(0.8 0.14 300);
  --code-token-punctuation: oklch(0.72 0.02 285);
  --code-token-link: oklch(0.78 0.13 235);

  /* diff — dark */
  --diff-add-line: oklch(0.5 0.11 150 / 0.22);
  --diff-add-emphasis: oklch(0.6 0.14 150 / 0.34);
  --diff-add-gutter: oklch(0.5 0.1 150 / 0.3);
  --diff-add-fg: oklch(0.82 0.13 150);
  --diff-del-line: oklch(0.55 0.16 22 / 0.24);
  --diff-del-emphasis: oklch(0.62 0.18 22 / 0.36);
  --diff-del-gutter: oklch(0.55 0.14 22 / 0.3);
  --diff-del-fg: oklch(0.78 0.15 22);
  --diff-context-fg: var(--muted-foreground);
  --diff-gutter-bg: oklch(from var(--muted) l c h / 0.4);
}

"use client";

import { useVirtualizer } from "@tanstack/react-virtual";
import { CheckIcon, CopyIcon } from "lucide-react";
import type { ComponentProps, CSSProperties, ReactNode } from "react";
import { Children, createContext, isValidElement, useContext, useEffect, useMemo, useRef, useState } from "react";

import type { CodeChrome, CodeDensity, CodeHighlight, CodeOverflow } from "@/components/control-ui/contracts";
import { useCopyToClipboard } from "@/components/control-ui/hooks/use-copy-to-clipboard";
import { cn } from "@/components/control-ui/lib/cn";
import { type CodeTokenLines, highlightToTokens } from "@/components/control-ui/lib/code-tokens";
import { skinSlot } from "@/components/control-ui/skin";
import { Button } from "@/components/control-ui/ui/button";
import { ScrollArea } from "@/components/control-ui/ui/scroll-area";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/control-ui/ui/tooltip";

/* Shared low-level code surface: gutter + code grid, token-colored via lib/code-tokens (Shiki CSS-vars,
 * follows skin), clean-copy structure (line numbers in select-none cells), optional TanStack virtualization.
 * CodeDiff and markdown fence renderer build on this same token renderer + row shape. */

// Above this line count, Code virtualizes rows even without an explicit `virtualize` prop.
const VIRTUALIZE_THRESHOLD = 200;
// Row height estimate for the virtualizer (measured precisely after paint via measureElement).
const ESTIMATED_LINE_HEIGHT = 20;

type CodeContextValue = { chrome: CodeChrome; density: CodeDensity; overflow: CodeOverflow; hasHeader: boolean };

const CodeContext = createContext<CodeContextValue | null>(null);

function useCodeContext(): CodeContextValue {
  const context = useContext(CodeContext);
  if (!context) throw new Error("Code compound parts must be rendered inside <Code>.");
  return context;
}

export type CodeProps = ComponentProps<"figure"> & {
  overflow?: CodeOverflow;
  chrome?: CodeChrome;
  density?: CodeDensity;
};

function hasCodeHeader(children: ReactNode) {
  return Children.toArray(children).some((child) => isValidElement(child) && child.type === CodeHeader);
}

export function Code({ overflow = "scroll", chrome = "standalone", density = "default", className, children, ...props }: CodeProps) {
  const isEmbedded = chrome === "embedded";
  const hasHeader = hasCodeHeader(children);

  return (
    <CodeContext.Provider value={{ chrome, density, overflow, hasHeader }}>
      <figure
        data-control-ui="code"
        data-slot="root"
        data-surface="panel"
        data-chrome={chrome}
        data-density={density}
        data-header={hasHeader ? "true" : undefined}
        className={cn(
          "min-w-0 [--nest-gap:0.5rem]",
          !hasHeader && "relative",
          isEmbedded
            ? "my-0 overflow-hidden rounded-none border-0 bg-transparent shadow-none ring-0"
            : "my-4 overflow-hidden rounded-panel bg-muted shadow-sm ring-1 ring-inset ring-border",
          skinSlot("code", "root", { chrome, density }),
          className,
        )}
        {...props}
      >
        {children}
      </figure>
    </CodeContext.Provider>
  );
}

export type CodeHeaderProps = ComponentProps<"figcaption">;

export function CodeHeader({ className, ...props }: CodeHeaderProps) {
  return (
    <figcaption
      data-control-ui="code"
      data-slot="header"
      className={cn("flex min-h-10 items-center justify-between gap-3 border-b px-3 py-1.5", skinSlot("code", "header", {}), className)}
      {...props}
    />
  );
}

export type CodeTitleProps = ComponentProps<"span">;

export function CodeTitle({ className, ...props }: CodeTitleProps) {
  return (
    <span
      data-control-ui="code"
      data-slot="title"
      className={cn("block min-w-0 truncate font-mono text-label text-muted-foreground", skinSlot("code", "title", {}), className)}
      {...props}
    />
  );
}

export type CodeActionsProps = ComponentProps<"div">;

export function CodeActions({ className, ...props }: CodeActionsProps) {
  return (
    <div
      data-control-ui="code"
      data-slot="actions"
      className={cn("flex shrink-0 items-center gap-1", skinSlot("code", "actions", {}), className)}
      {...props}
    />
  );
}

export type CodeCopyProps = Omit<ComponentProps<typeof Button>, "children" | "onClick"> & {
  value: string;
  children?: ReactNode;
  copiedLabel?: ReactNode;
  copiedAriaLabel?: string;
};

// Copy control IS the library Button (quiet variant), so it stays in lockstep with every other control, no bespoke styling.
export function CodeCopy({
  value,
  copiedLabel = "Copied",
  copiedAriaLabel = "Copied",
  children = "Copy",
  "aria-label": ariaLabel,
  ...props
}: CodeCopyProps) {
  const { isCopied, handleCopy } = useCopyToClipboard({ text: value });
  return (
    <Button
      type="button"
      variant="quiet"
      size="xs"
      aria-live="polite"
      aria-label={isCopied && ariaLabel ? copiedAriaLabel : ariaLabel}
      {...props}
      onClick={handleCopy}
    >
      {isCopied ? copiedLabel : children}
    </Button>
  );
}

export type CodeFloatingCopyProps = Omit<CodeCopyProps, "children" | "copiedLabel">;

export function CodeFloatingCopy({ className, "aria-label": ariaLabel = "Copy code", ...props }: CodeFloatingCopyProps) {
  return (
    <TooltipProvider delay={0}>
      <Tooltip>
        <TooltipTrigger asChild>
          <CodeCopy
            aria-label={ariaLabel}
            className={cn(
              "absolute top-2 right-2 z-10 size-7 bg-background/85 p-0 shadow-sm ring-1 ring-inset ring-border backdrop-blur",
              className,
            )}
            copiedLabel={<CheckIcon aria-hidden="true" className="size-3.5" />}
            {...props}
          >
            <CopyIcon aria-hidden="true" className="size-3.5" />
          </CodeCopy>
        </TooltipTrigger>
        <TooltipContent side="left">{ariaLabel}</TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

/** Client-side highlighting: when `tokens` unset, tokenize in a cancellable effect keyed by lang+code.
 *  Returns null until resolved, or when highlighting off / language unknown — callers fall back to plain text. */
export function useCodeTokens({
  code,
  lang,
  tokens,
  highlight,
}: {
  code: string;
  lang?: string;
  tokens?: CodeTokenLines | null;
  highlight: CodeHighlight;
}): CodeTokenLines | null {
  const requestKey = `${lang ?? ""}\n${code}`;
  const [clientTokens, setClientTokens] = useState<{ key: string; tokens: CodeTokenLines | null } | null>(null);

  useEffect(() => {
    if (highlight === "none" || tokens !== undefined || !lang) return;
    let cancelled = false;
    void highlightToTokens(code, lang)
      .then((result) => {
        if (!cancelled) setClientTokens({ key: requestKey, tokens: result });
      })
      .catch(() => {
        if (!cancelled) setClientTokens({ key: requestKey, tokens: null });
      });
    return () => {
      cancelled = true;
    };
  }, [code, lang, tokens, highlight, requestKey]);

  if (highlight === "none") return null;
  if (tokens !== undefined) return tokens;
  return clientTokens?.key === requestKey ? clientTokens.tokens : null;
}

/** Renders one line's Shiki tokens as colored spans. Shared by Code and CodeDiff. */
export function CodeTokenLine({ tokens, plain }: { tokens: CodeTokenLines[number] | null; plain: string }): ReactNode {
  if (!tokens || tokens.length === 0) return plain;
  return tokens.map((token, index) => {
    const style: CSSProperties = { ...token.style };
    return (
      // biome-ignore lint/suspicious/noArrayIndexKey: token order is the identity within a line
      <span key={index} style={style}>
        {token.content}
      </span>
    );
  });
}

// Select-none gutter + code cell, kept flat so text selection over the code column copies clean source.
function CodeRow({
  index,
  number,
  tokens,
  plain,
  overflow,
  showLineNumbers,
  measureRef,
  style,
}: {
  index?: number;
  number: number;
  tokens: CodeTokenLines[number] | null;
  plain: string;
  overflow: CodeOverflow;
  showLineNumbers: boolean;
  measureRef?: (node: HTMLDivElement | null) => void;
  style?: CSSProperties;
}) {
  return (
    <div
      ref={measureRef}
      data-index={index}
      data-control-ui="code"
      data-slot="line"
      className={cn("flex min-h-5 w-full", skinSlot("code", "line", {}))}
      style={style}
    >
      {showLineNumbers ? (
        <span
          data-control-ui="code"
          data-slot="gutter"
          aria-hidden="true"
          className={cn("shrink-0 select-none pr-3 pl-4 text-right tabular-nums text-muted-foreground/60", skinSlot("code", "gutter", {}))}
          style={{ minWidth: "3.5rem" }}
        >
          {number}
        </span>
      ) : null}
      <code
        className={cn(
          "min-w-0 flex-1 pr-4",
          overflow === "wrap" ? "whitespace-pre-wrap break-words" : "whitespace-pre",
          !showLineNumbers && "pl-4",
        )}
      >
        <CodeTokenLine tokens={tokens} plain={plain} />
      </code>
    </div>
  );
}

export type CodeContentProps = Omit<ComponentProps<"div">, "children"> & {
  code: string;
  lang?: string;
  tokens?: CodeTokenLines | null;
  highlight?: CodeHighlight;
  showLineNumbers?: boolean;
  startLine?: number;
  maxHeight?: string;
  virtualize?: boolean;
};

export function CodeContent({
  code,
  lang,
  tokens,
  highlight = "auto",
  showLineNumbers = false,
  startLine = 1,
  maxHeight = "32rem",
  virtualize,
  className,
  ref,
  style,
  ...props
}: CodeContentProps) {
  const { density, overflow, hasHeader } = useCodeContext();
  const resolvedTokens = useCodeTokens({ code, lang, tokens, highlight });
  const plainLines = useMemo(() => code.split("\n"), [code]);
  const isCompact = density === "compact";

  const scrollRef = useRef<HTMLDivElement>(null);
  function setScrollElement(node: HTMLDivElement | null) {
    scrollRef.current = node;
    if (typeof ref === "function") ref(node);
    else if (ref) ref.current = node;
  }
  const shouldVirtualize = virtualize ?? plainLines.length > VIRTUALIZE_THRESHOLD;
  const useScrollArea = density !== "compact" || overflow !== "wrap";

  // react-doctor-disable-next-line react-hooks-js/incompatible-library
  const virtualizer = useVirtualizer({
    count: plainLines.length,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => ESTIMATED_LINE_HEIGHT,
    overscan: 24,
    enabled: shouldVirtualize,
  });

  const gridClassName = cn(
    // The `color:` label keeps tailwind-merge from treating the arbitrary color utility as font size.
    "font-mono leading-5 text-[color:var(--code-foreground)]",
    isCompact ? "py-2 text-micro" : "py-3 text-label",
    overflow === "scroll" ? "w-max min-w-full" : "w-full",
  );

  const grid = shouldVirtualize ? (
    <>
      <pre data-control-ui="code" data-slot="accessible-source" className="sr-only">
        <code>{code}</code>
      </pre>
      <div aria-hidden="true" className={gridClassName} style={{ position: "relative", height: `${virtualizer.getTotalSize()}px` }}>
        {virtualizer.getVirtualItems().map((item) => (
          <CodeRow
            key={item.key}
            index={item.index}
            number={startLine + item.index}
            tokens={resolvedTokens?.[item.index] ?? null}
            plain={plainLines[item.index] ?? ""}
            overflow={overflow}
            showLineNumbers={showLineNumbers}
            measureRef={virtualizer.measureElement}
            style={{ position: "absolute", top: 0, left: 0, width: "100%", transform: `translateY(${item.start}px)` }}
          />
        ))}
      </div>
    </>
  ) : (
    <div className={gridClassName}>
      {plainLines.map((plain, index) => (
        <CodeRow
          // biome-ignore lint/suspicious/noArrayIndexKey: line position is the row identity
          key={index}
          number={startLine + index}
          tokens={resolvedTokens?.[index] ?? null}
          plain={plain}
          overflow={overflow}
          showLineNumbers={showLineNumbers}
        />
      ))}
    </div>
  );

  const content = useScrollArea ? (
    <ScrollArea
      maxHeight={maxHeight}
      viewportClassName={cn(skinSlot("code", "content", {}), className)}
      viewportProps={{ ...props, "data-control-ui": "code", "data-slot": "content", style }}
      viewportRef={setScrollElement}
    >
      {grid}
    </ScrollArea>
  ) : (
    <div
      ref={setScrollElement}
      data-control-ui="code"
      data-slot="content"
      className={cn("overflow-auto", skinSlot("code", "content", {}), className)}
      style={{ ...style, maxHeight }}
      {...props}
    >
      {grid}
    </div>
  );

  if (hasHeader) return content;

  return (
    <div className="relative pt-10">
      <CodeFloatingCopy value={code} />
      {content}
    </div>
  );
}
